package main

import (
"encoding/json"
"fmt"
"log"

"github.com/golang-jwt/jwt/v5"
)

func extractActorTypeFromJWT(tokenString string) (string, error) {
	token, _, err := new(jwt.Parser).ParseUnverified(tokenString, jwt.MapClaims{})
	if err != nil {
		return "", err
	}

	claims, ok := token.Claims.(jwt.MapClaims)
	if !ok {
		return "", fmt.Errorf("failed to parse claims")
	}

	actorType, exists := claims["actor_type"].(string)
	if !exists {
		return "", fmt.Errorf("actor_type not found in token")
	}

	return actorType, nil
}

